let metrics = match exec_output {
    Some(bytes) => match decode_llm_response(bytes, is_encrypted_output) {
        Ok(metrics) => metrics,
        Err(err) => return Err(format!("Failed to decode LLM response: {err}")),
    },
    None => return Err("Missing LLM executor output".to_string()),
};
let config = resolve_llm_model_config(db, model_registry_contract, metrics.model.as_deref(), model_cache)?;

let model_name = model.ok_or_else(|| "LLM response did not include a model".to_string())?;
let info = read_model_from_db_cached(db, contract, model_name, cache)?
    .ok_or_else(|| format!("Model '{model_name}' not in LLM registry"))?;
